1	\chapter{The relative cotangent presheaf}
2	\label{chap:differentials}
3	
4	This chapter develops the relative cotangent \emph{presheaf} $\Omega_{X/S}$ of a morphism of schemes $f \colon X \to S$, starting from the ring-theoretic K\"ahler differential module $\Omega_{B/A}$ already available in Mathlib. The output is a presheaf of $\struct{X}$-modules whose sections on each open $V \subseteq X$ are the K\"ahler differential module of the ring map $(f^{-1}_{\mathrm{psh}}\struct{S})(V) \to \struct{X}(V)$ induced by $f$, where $f^{-1}_{\mathrm{psh}}$ denotes the \emph{presheaf-level} inverse-image functor (left Kan extension along $(\mathrm{Opens.map}\,f.\mathrm{base}).\mathrm{op}$).
5	
6	The downstream role of this chapter is to provide the \emph{forward direction} of the standard smoothness criterion: smoothness of $f$ implies that on every affine chart $V \to U$ (with $V \subseteq X$, $U \subseteq S$ affine and $f V \subseteq U$) the appLE-algebra K\"ahler differential $\Omega_{\Gamma(X, V)\,/\,\Gamma(S, U)}$ is a free $\Gamma(X, V)$-module of rank $n$. This is the Jacobian-criterion direction and is what connects to the dimension hypothesis on the Jacobian: the smoothness of the curve $C \to \Spec k$ in the Jacobian definition is the special case $n = 1$, and the relative dimension of $\Jac(C)$ is read off from the rank via the same forward implication. The relationship between this affine-chart-wise algebra-K\"ahler form and the section module of the relative cotangent presheaf $\Omega_{X/S}$ is the content of milestone~M1 of the project roadmap and is stated as Theorem~\ref{thm:relativeDifferentialsPresheaf_iso_kaehler_appLE} in Section~\ref{sec:bridge}. The converse implication is \emph{mathematically false} as stated and is documented separately in Section~\ref{sec:converse-out-of-scope}.
7	
8	\section{The relative cotangent presheaf}
9	
10	\begin{definition}
11	
12	\leanok
13	[Relative cotangent presheaf of a morphism]
14	  \label{def:relative_kaehler_presheaf}
15	  \lean{AlgebraicGeometry.Scheme.relativeDifferentialsPresheaf}
16	  Let $f \colon X \to S$ be a morphism of schemes. The presheaf-level inverse-image presheaf of rings $f^{-1}_{\mathrm{psh}}\struct{S}$ on $X$ (the left Kan extension of $\struct{S}$ along $(\mathrm{Opens.map}\,f.\mathrm{base}).\mathrm{op}$, given on each open $V \subseteq X$ by the colimit $\mathrm{colim}_{W : \,f V \subseteq W \subseteq S}\,\struct{S}(W)$) is paired with $\struct{X}$ by the canonical adjunction-transpose $f^{-1}_{\mathrm{psh}}\struct{S} \to \struct{X}$ of the comorphism $f^{\sharp}\colon\struct{S}\to f_{*}\struct{X}$. Applying the presheaf-of-modules K\"ahler differential construction $\mathrm{relativeDifferentials}'$ to this map of presheaves of commutative rings produces a presheaf of $\struct{X}$-modules on $X$, the \emph{relative cotangent presheaf} $\Omega_{X/S}$.
17	\end{definition}
18	
19	\begin{lemma}
20	
21	\leanok
22	[Sections of $\Omega_{X/S}$ on an open]
23	  \label{lem:relative_kaehler_presheaf_obj}
24	  \lean{AlgebraicGeometry.Scheme.relativeDifferentialsPresheaf_obj_kaehler}
25	  \uses{def:relative_kaehler_presheaf}
26	  For every open $V \subseteq X$, the sections of the relative cotangent presheaf are, by construction, the K\"ahler differential module of the ring map $(f^{-1}_{\mathrm{psh}}\struct{S})(V) \to \struct{X}(V)$ induced by $f$:
27	  \[
28	    \Omega_{X/S}(V) \;=\; \Omega_{\struct{X}(V) \,/\, (f^{-1}_{\mathrm{psh}}\struct{S})(V)}.
29	  \]
30	  Here $(f^{-1}_{\mathrm{psh}}\struct{S})(V) = \mathrm{colim}_{W : \,f V \subseteq W \subseteq S}\,\struct{S}(W)$ is the presheaf-level inverse-image section ring, \emph{not} $\struct{S}(U)$ for an arbitrary affine open $U \supseteq f V$. The relationship between this colimit-source K\"ahler module and the classical ring-theoretic $\Omega_{B/A}$ for $A = \struct{S}(U)$, $B = \struct{X}(V)$ on an affine chart $V = \Spec B \subseteq f^{-1}U$ with $U = \Spec A \subseteq S$ affine is the content of the bridge documented in Section~\ref{sec:bridge-out-of-scope}.
31	\end{lemma}
32	
33	\begin{proof}
34	  \uses{def:relative_kaehler_presheaf}
35	  \leanok
36	  By definition of $\mathrm{relativeDifferentials}'$: the construction is built object-wise to be the Mathlib \texttt{KaehlerDifferential} module of the ring map at each open. The identification is therefore by \texttt{rfl} after unfolding the definition. The colimit description of $(f^{-1}_{\mathrm{psh}}\struct{S})(V)$ is the definition of \texttt{TopCat.Presheaf.pullback} as the left Kan extension along $(\mathrm{Opens.map}\,f.\mathrm{base}).\mathrm{op}$ in Mathlib.
37	\end{proof}
38	
39	\begin{remark}[Comparison with Mathlib's ring-level $\Omega_{B/A}$]
40	  \label{rem:kahler_compatibility}
41	  Mathlib provides the ring-theoretic K\"ahler differential module $\Omega_{B/A}$ together with the universal derivation $\mathrm{d} \colon B \to \Omega_{B/A}$. The construction of $\Omega_{X/S}$ on each open is, by definition, this Mathlib module applied at the ring level of the presheaf, so all ring-level Mathlib lemmas about $\Omega_{B/A}$ transfer verbatim under Lemma~\ref{lem:relative_kaehler_presheaf_obj} — but for the \emph{colimit-source} ring $(f^{-1}_{\mathrm{psh}}\struct{S})(V)$, not for $\struct{S}(U)$. Transferring to the classical $A = \struct{S}(U)$ source on an affine chart is the bridge of Section~\ref{sec:bridge-out-of-scope}.
42	\end{remark}
43	
44	\section{Smoothness criterion for $\Omega_{X/S}$ (forward direction)}
45	
46	The forward direction of the textbook smoothness criterion identifies a necessary condition on the relative K\"ahler differentials: every point of $X$ admits an affine chart $V \to U$ over which the appLE-algebra K\"ahler module $\Omega_{B/A}$ is free of the prescribed rank, with $A = \struct{S}(U)$ and $B = \struct{X}(V)$. This is the global version of the algebraic-side fact that an \texttt{Algebra.IsStandardSmoothOfRelativeDimension}~$n$~algebra has a free K\"ahler differential module of rank $n$. We state and prove the theorem directly on the appLE-algebra K\"ahler module, sidestepping the presheaf bridge of Section~\ref{sec:bridge-out-of-scope}. The converse implication (a local-freeness hypothesis on $\Omega$ alone implying smoothness) is \emph{false}; see Section~\ref{sec:converse-out-of-scope}.
47	
48	\begin{theorem}\leanok
49	[Smooth implies $\Omega$ locally free (algebra-K\"ahler form)]
50	  \label{thm:smooth_locally_free_omega}
51	  \lean{AlgebraicGeometry.Scheme.smooth_locally_free_omega}
52	  \uses{def:relative_kaehler_presheaf}
53	  Let $f \colon X \to S$ be a morphism of schemes and let $n \in \mathbb{N}$. If $f$ is smooth of relative dimension $n$, then for every point $x \in X$ there exist an affine open $U \subseteq S$, an affine open $V \subseteq X$ with $x \in V$ and $V \subseteq f^{-1}(U)$, such that the K\"ahler differential module
54	  \[
55	    \Omega_{\Gamma(X, V) \,/\, \Gamma(S, U)}
56	  \]
57	  (over the appLE algebra structure $\Gamma(S, U) \to \Gamma(X, V)$ induced by $f$) is a free $\Gamma(X, V)$-module of rank $n$.
58	\end{theorem}
59	
60	\begin{proof}
61	  \uses{def:relative_kaehler_presheaf}
62	  \leanok
63	  Fix $x \in X$. We use the abbreviation $A := \Gamma(S, U)$ and $B := \Gamma(X, V)$ for the section rings on the affine chart we will produce; the algebra map $A \to B$ is the appLE map $(f.\mathrm{appLE}\,U\,V\,e).\mathrm{hom}$ induced by $f$.
64	
65	  \emph{Step 1: extract a standard-smooth chart at $x$.} The auto-generated \texttt{mk\_iff} bridge
66	  \[
67	    \texttt{AlgebraicGeometry.smoothOfRelativeDimension\_iff} \quad [\text{verified}]
68	  \]
69	  (\texttt{Mathlib.AlgebraicGeometry.Morphisms.Smooth}; produced by the \texttt{@[mk\_iff]} attribute on the class \texttt{SmoothOfRelativeDimension}) unfolds the hypothesis \texttt{SmoothOfRelativeDimension}~$n$~$f$ into: for every $x \in X$, there exist affine opens $U \subseteq S$ and $V \subseteq X$ with $x \in V$ and $V \leq f^{-1}U$, such that the induced algebra map $(f.\mathrm{appLE}\,U\,V\,e).\mathrm{hom}\colon A \to B$ satisfies \texttt{Algebra.IsStandardSmoothOfRelativeDimension}~$n$~$A$~$B$.
70	
71	  \emph{Step 2: pass to plain standard-smooth.} The lemma
72	  \[
73	    \texttt{Algebra.IsStandardSmoothOfRelativeDimension.isStandardSmooth} \quad [\text{verified}]
74	  \]
75	  (\texttt{Mathlib.RingTheory.Smooth.StandardSmooth}) yields \texttt{Algebra.IsStandardSmooth}~$A$~$B$ from the relative-dimension-tagged form, unlocking the cotangent-module machinery in the next two steps.
76	
77	  \emph{Step 3: free K\"ahler module on the chart.} The Mathlib instance
78	  \[
79	    \texttt{Algebra.IsStandardSmooth.free\_kaehlerDifferential} \quad [\text{verified}]
80	  \]
81	  (\texttt{Mathlib.RingTheory.Smooth.StandardSmoothCotangent}) synthesises \texttt{Module.Free}~$B$~$\Omega_{B/A}$ from \texttt{Algebra.IsStandardSmooth}~$A$~$B$.
82	
83	  \emph{Step 4: pin the rank.} The theorem
84	  \[
85	    \texttt{Algebra.IsStandardSmoothOfRelativeDimension.rank\_kaehlerDifferential} \quad [\text{verified}]
86	  \]
87	  (same file as Step 3) gives $\rank_B\,\Omega_{B/A} = n$ under the hypotheses \texttt{Nontrivial}~$B$ and \texttt{Algebra.IsStandardSmoothOfRelativeDimension}~$n$~$A$~$B$.
88	
89	  \emph{Step 4.5: discharge the \texttt{Nontrivial}~$B$ side condition.} The chart witness $x \in V$ shows that the open $V \subseteq X$ is non-empty as a set, so its structure-sheaf section ring $B = \Gamma(X, V) = \struct{X}(V)$ is non-zero by \texttt{AlgebraicGeometry.Scheme.component\_nontrivial} (the structure sheaf of a scheme has \texttt{Nontrivial} sections on a non-empty open). This supplies the \texttt{Nontrivial}~$B$ hypothesis required by Step 4.
90	
91	  Combining Steps 1--4.5, the chart $(U, V, e)$ produced by Step 1 satisfies $x \in V$, $\mathrm{IsAffineOpen}\,U$, $\mathrm{IsAffineOpen}\,V$, and under the appLE algebra structure $A = \Gamma(S, U) \to B = \Gamma(X, V)$, the K\"ahler module $\Omega_{B/A}$ is a free $B$-module of rank $n$. As $x \in X$ was arbitrary, the statement follows.
92	
93	  This is the forward direction of the Jacobian criterion: Stacks Tag~02G1 (and Hartshorne~II.8, Theorem~II.5.2 in the Noetherian case).
94	
95	  \emph{Mathlib name summary.} The five \texttt{[verified]} closure pieces the proof relies on are
96	  \texttt{AlgebraicGeometry.smoothOfRelativeDimension\_iff} (Step 1),
97	  \texttt{Algebra.IsStandardSmoothOfRelativeDimension.isStandardSmooth} (Step 2),
98	  \texttt{Algebra.IsStandardSmooth.free\_kaehlerDifferential} (Step 3),
99	  \texttt{Algebra.IsStandardSmoothOfRelativeDimension.rank\_kaehlerDifferential} (Step 4),
100	  and \texttt{AlgebraicGeometry.Scheme.component\_nontrivial} (Step 4.5).
101	\end{proof}
102	
103	\begin{remark}[Lean naming]
104	  \label{rem:smooth_class_naming}
105	  The Lean class for ``smooth of relative dimension $n$'' is \texttt{AlgebraicGeometry.SmoothOfRelativeDimension}; the spelling \texttt{IsSmoothOfRelativeDimension} that appeared in earlier iterations of this project is a deprecated alias in Mathlib \texttt{b80f227}. The \texttt{\textbackslash lean\{...\}} hint above names the non-deprecated form.
106	\end{remark}
107	
108	\section{Bridge: presheaf form $\leftrightarrow$ algebra-K\"ahler form on an affine chart (milestone M1)}
109	\label{sec:bridge}
110	
111	Theorem~\ref{thm:smooth_locally_free_omega} is stated in the \emph{algebra-K\"ahler form} $\Omega_{\Gamma(X, V) / \Gamma(S, U)}$ for an affine chart $V \subseteq f^{-1}U$, while the relative cotangent presheaf $\Omega_{X/S}$ of Definition~\ref{def:relative_kaehler_presheaf} carries on its section over $V$ the K\"ahler module $\Omega_{\Gamma(X, V) / A_{\mathrm{colim}}}$ over the presheaf-level inverse-image colimit ring $A_{\mathrm{colim}} = (f^{-1}_{\mathrm{psh}}\struct{S})(V) = \mathrm{colim}_{W :\, f V \subseteq W \subseteq S}\,\struct{S}(W)$. On a single affine chart the two are connected by a canonical $B$-linear isomorphism whose construction is the content of milestone~M1 of the project roadmap (\texttt{STRATEGY.md}).
112	
113	\begin{theorem}[Bridge between presheaf and algebra-K\"ahler forms]
114	  \label{thm:relativeDifferentialsPresheaf_iso_kaehler_appLE}
115	  \lean{AlgebraicGeometry.Scheme.relativeDifferentialsPresheaf_iso_kaehler_appLE}
116	  \uses{def:relative_kaehler_presheaf, lem:relative_kaehler_presheaf_obj, lem:appLE_isLocalization}
117	  Let $f \colon X \to S$ be a morphism of schemes, let $U \subseteq S$ and $V \subseteq X$ be affine opens with $V \leq f^{-1}U$, and write $A := \Gamma(S, U)$, $B := \Gamma(X, V)$, with the appLE algebra structure $A \to B$ induced by $f$. There is a canonical $B$-linear isomorphism
118	  \[
119	    (\mathrm{relativeDifferentialsPresheaf}\,f).\mathrm{presheaf}(V)
120	    \;\cong_{B}\;
121	    \Omega_{B \,/\, A}
122	  \]
123	  identifying the section module of the relative cotangent presheaf on $V$ with the appLE-algebra K\"ahler differential module of Theorem~\ref{thm:smooth_locally_free_omega}.
124	\end{theorem}
125	
126	\begin{proof}
127	  \uses{def:relative_kaehler_presheaf, lem:relative_kaehler_presheaf_obj, lem:appLE_isLocalization, lem:kaehler_localization_subsingleton, lem:kaehler_quotient_localization_iso}
128	  \leanok
129	  The proof decomposes into the four sub-steps M1.a--M1.e of the roadmap. We use the abbreviation $A_{\mathrm{colim}} := (f^{-1}_{\mathrm{psh}}\struct{S})(V) = \mathrm{colim}_{W :\, f V \subseteq W \subseteq S}\,\struct{S}(W)$ for the colimit ring carrying the presheaf-side K\"ahler module.
130	
131	  \emph{M1.a: the multiplicative set of ``good'' elements.} Define
132	  \[
133	    M \;:=\; \{\, g \in A \,:\, (f.\mathrm{appLE}\,U\,V\,e).\mathrm{hom}(g) \in B^{\times} \,\}
134	  \]
135	  as the set of elements of $A$ whose image in $B$ is a unit. $M$ is a submonoid: $1 \in M$ (the appLE map is a ring homomorphism, so $\mathrm{appLE}(1) = 1$, a unit), and if $g, h \in M$ then $\mathrm{appLE}(gh) = \mathrm{appLE}(g)\,\mathrm{appLE}(h) \in B^{\times}$ as the product of two units.
136	
137	  \emph{M1.b: $A \to A_{\mathrm{colim}}$ is the localization at $M$.} This is the heart of the bridge and is the standalone Mathlib contribution candidate; see Lemma~\ref{lem:appLE_isLocalization} below for the statement. The argument: the directed system $\{W \subseteq S : f V \subseteq W\}$ admits a cofinal subsystem of basic opens $D(g) \subseteq U$ with $g \in M$ (these are exactly the affine opens between $f V$ and $U$ on which $g$ becomes a unit after pulling back to $B$, by $V \subseteq f^{-1}D(g) \iff \mathrm{appLE}(g) \in B^{\times}$); for each such $g$, the section ring $\struct{S}(D(g)) = A_{g}$ is the localization of $A$ at $g$ (Mathlib's \texttt{IsAffineOpen.basicOpen\_isLocalization}); and the directed colimit of these localizations over $M$ is the localization $A_{M}$ of $A$ at the full multiplicative set $M$.
138	
139	  \emph{M1.c: the K\"ahler module of a localization is trivial.} Lemma~\ref{lem:kaehler_localization_subsingleton} below: if $A \to L$ is a localization at a multiplicative subset $M \subseteq A$, then $\Omega_{L/A}$ is subsingleton (equivalently, zero as an $L$-module). Reason: every element of $L$ is of the form $a / g$ with $a \in A$, $g \in M$, and $\mathrm{d}(a/g) = (\mathrm{d}a - (a/g)\,\mathrm{d}g)/g = 0$ in $\Omega_{L/A}$ (both $\mathrm{d}a$ and $\mathrm{d}g$ vanish, being images of elements of $A$ under a derivation over $A$); since $L$ is generated by such elements and $\mathrm{d}$ is a universal derivation, the whole module is zero. Mathlib \texttt{b80f227} has \emph{no off-the-shelf} bare lemma for ``$\Omega_{L/A}$ is subsingleton when $A \to L$ is a localization''; the closest is \texttt{Algebra.IsStandardSmoothOfRelationDimension.subsingleton\_kaehlerDifferential} (which requires the much stronger \texttt{IsStandardSmoothOfRelativeDimension 0 R S}). This M1.c sub-lemma is therefore a genuine Mathlib gap-fill: the proof is short (10--30 LOC), uses the universal property of the K\"ahler differential module plus the fact that $\mathrm{d}$ kills units (via the formula $\mathrm{d}(g g^{-1}) = 0 = g \,\mathrm{d}(g^{-1}) + g^{-1}\,\mathrm{d}g$, so $\mathrm{d}(g^{-1}) = -g^{-2}\,\mathrm{d}g$, which is zero when $g \in A$). Candidate Mathlib home: \texttt{Mathlib.RingTheory.Kaehler.Basic}.
140	
141	  \emph{M1.d: the surjection $\Omega_{B/A} \twoheadrightarrow \Omega_{B/A_{\mathrm{colim}}}$ is an iso.} Apply Lemma~\ref{lem:kaehler_quotient_localization_iso} below (\texttt{KaehlerDifferential.isLocalizedModule\_map} in Mathlib \texttt{RingTheory.Etale.Kaehler}, plus the M1.c conclusion that $\Omega_{A_{\mathrm{colim}}/A} = 0$). The second fundamental exact sequence
142	  \[
143	    B \otimes_{A_{\mathrm{colim}}} \Omega_{A_{\mathrm{colim}} / A}
144	    \;\longrightarrow\; \Omega_{B / A}
145	    \;\twoheadrightarrow\; \Omega_{B / A_{\mathrm{colim}}}
146	    \;\longrightarrow\; 0
147	  \]
148	  has zero left-hand term by M1.c, so the right-hand surjection is an iso.
149	
150	  \emph{M1.e: combine with the $\mathrm{rfl}$-identification of the presheaf section.} By Lemma~\ref{lem:relative_kaehler_presheaf_obj}, $(\mathrm{relativeDifferentialsPresheaf}\,f).\mathrm{presheaf}(V) = \Omega_{B / A_{\mathrm{colim}}}$ definitionally. Composing the rfl-equality with the inverse of the M1.d iso gives the claimed $B$-linear isomorphism.
151	\end{proof}
152	
153	\begin{lemma}[$A \to A_{\mathrm{colim}}$ is a localization at $M$]
154	  \label{lem:appLE_isLocalization}
155	  \lean{AlgebraicGeometry.Scheme.appLE_isLocalization}
156	  \uses{def:relative_kaehler_presheaf}
157	  In the setting of Theorem~\ref{thm:relativeDifferentialsPresheaf_iso_kaehler_appLE}, the canonical ring homomorphism $A \to A_{\mathrm{colim}}$ exhibits $A_{\mathrm{colim}}$ as the localization of $A$ at the multiplicative set $M := \{g \in A : (f.\mathrm{appLE}\,U\,V\,e).\mathrm{hom}(g) \in B^{\times}\}$.
158	\end{lemma}
159	
160	\begin{proof}
161	  \uses{def:relative_kaehler_presheaf}
162	  The proof is the cofinality argument of step M1.b above. The directed system $\{W \subseteq S : f V \subseteq W \subseteq U\}$ admits the cofinal subfamily $\{D(g) : g \in M\}$ (because every open $W$ between $f V$ and $U$ contains a basic open $D(g)$ also between $f V$ and $U$, and $f V \subseteq D(g)$ iff $g$ is a unit in $B = \Gamma(X, V)$ by the pullback characterisation of basic opens). The colimit over the cofinal subfamily of localizations $A_g$ equals the localization $A_M$ at the full multiplicative set $M$ (this is the standard fact that localization at a multiplicative set is the directed colimit of localizations at finitely-generated sub-monoids). Mathlib leverage: \texttt{AlgebraicGeometry.IsAffineOpen.isLocalization\_basicOpen} \texttt{[verified]} (\texttt{Mathlib.AlgebraicGeometry.AffineScheme}) for the $A_g$ identification (\texttt{IsLocalization.Away} on the basic-open section ring), plus a cofinality-of-directed-colimit lemma that may need to be supplied as part of M1.b (this is the Mathlib contribution component of milestone~M1). The Mathlib analogist's persistent file \texttt{analogies/relative-differentials-presheaf-bridge.md} (this iter) records the design rationale for the chosen API shape.
163	\end{proof}
164	
165	\begin{lemma}[K\"ahler module of a localization is trivial]
166	  \label{lem:kaehler_localization_subsingleton}
167	  \lean{AlgebraicGeometry.Scheme.kaehler_localization_subsingleton}
168	  \uses{lem:appLE_isLocalization}
169	  Let $A \to L$ be a localization at a multiplicative subset $M \subseteq A$. Then $\Omega_{L / A}$ is subsingleton (the zero $L$-module).
170	\end{lemma}
171	
172	\begin{proof}
173	  Every element of $L$ is of the form $\iota(a)\,\iota(g)^{-1}$ for some $a \in A$ and $g \in M$ (where $\iota \colon A \to L$ is the structure map). In $\Omega_{L/A}$, the universal derivation $\mathrm{d}$ over $A$ kills $\iota(a)$ and $\iota(g)$ (both are images of $A$-elements). Therefore $\mathrm{d}(\iota(a)\,\iota(g)^{-1}) = 0$ via the quotient rule, and the image of $\mathrm{d} \colon L \to \Omega_{L/A}$ is zero. Since $\Omega_{L/A}$ is generated as an $L$-module by $\mathrm{d}(L)$ (the universal property), the whole module is zero. Mathlib's \texttt{KaehlerDifferential.subsingleton\_of\_isLocalization} packages this conclusion when available; otherwise the proof is a direct application of the universal property of \texttt{KaehlerDifferential} as a quotient of $L \otimes_{\mathbb Z} L$ modulo the Leibniz / $A$-linearity relations.
174	\end{proof}
175	
176	\begin{lemma}[Tower-cancellation iso for K\"ahler modules under localization]
177	  \label{lem:kaehler_quotient_localization_iso}
178	  \lean{AlgebraicGeometry.Scheme.kaehler_quotient_localization_iso}
179	  \uses{lem:kaehler_localization_subsingleton}
180	  Let $A \to L$ be a localization (in the sense of \texttt{IsLocalization}), and let $L \to B$ be a ring map. Then the canonical surjection $\Omega_{B/A} \twoheadrightarrow \Omega_{B/L}$ induced by the tower is a $B$-linear isomorphism.
181	\end{lemma}
182	
183	\begin{proof}
184	  \uses{lem:kaehler_localization_subsingleton}
185	  The second fundamental exact sequence of K\"ahler differentials reads
186	  \[
187	    B \otimes_{L} \Omega_{L/A} \;\longrightarrow\; \Omega_{B/A} \;\twoheadrightarrow\; \Omega_{B/L} \;\longrightarrow\; 0.
188	  \]
189	  By Lemma~\ref{lem:kaehler_localization_subsingleton}, the left term vanishes. Therefore the right surjection has zero kernel, i.e.\ is a $B$-linear iso. Mathlib's \texttt{KaehlerDifferential.isLocalizedModule\_map} (\texttt{Mathlib.RingTheory.Etale.Kaehler}) packages the same conclusion via the surjection-with-zero-kernel argument; in the project we may either reuse this lemma directly (preferred) or write the second-fundamental-sequence argument inline if the Mathlib name is not in the pinned snapshot.
190	\end{proof}
191	
192	\begin{remark}[Mathlib contribution candidate]
193	  \label{rem:bridge_mathlib_pr}
194	  Lemma~\ref{lem:appLE_isLocalization} is the genuine Mathlib contribution candidate of milestone~M1. The statement is general (no curve-specific or Jacobian-specific content), the proof is short once the cofinality lemma is in place, and the use case is broad (every appLE-restriction of a morphism of schemes between affine charts). Candidate Mathlib homes:
195	  \begin{itemize}
196	    \item \texttt{Mathlib.AlgebraicGeometry.Presheaf.InverseImage} (new file, with the cofinality lemma as a stand-alone result);
197	    \item \texttt{Mathlib.AlgebraicGeometry.Morphisms.AffineChart} (specialisation to morphisms of schemes between affine charts).
198	  \end{itemize}
199	\end{remark>
200	
201	\section{Converse direction --- out of autonomous-loop scope}
202	\label{sec:converse-out-of-scope}
203	
204	The reverse implication
205	\[
206	  \forall x\in X,\ \exists\,U\text{ affine},\ \Omega_{X/S}(U)\text{ free of rank }n
207	  \quad\Longrightarrow\quad f \text{ smooth of relative dimension } n
208	\]
209	is \emph{mathematically false} as stated, even under the auxiliary hypothesis that $f$ is locally of finite presentation. Local freeness of $\Omega$ alone does not imply flatness, and flatness (equivalently, formal smoothness via vanishing of the first Andr\'e--Quillen cohomology) is genuine deformation-theoretic content not encoded in the section-module hypothesis. This is why the iff form of the criterion present in earlier iterations was demoted to a forward implication.
210	
211	\begin{remark}[Explicit counterexample]
212	  \label{rem:converse_counterexample}
213	  Let $k$ be a field and consider the morphism $f \colon \Spec k \to \Spec k[t]$ induced by the surjection $k[t] \twoheadrightarrow k$ sending $t \mapsto 0$. Then $f$ is locally of finite presentation, its source $\Spec k$ has a unique affine open (itself), and the K\"ahler differential module $\Omega_{k/k[t]} = 0$ is free of rank $0$ (the trivial \texttt{Module.Basis} indexed by the empty set witnesses this). Yet $f$ is the closed immersion of a non-open point of $\Spec k[t]$, hence is not flat and therefore not smooth, so \texttt{SmoothOfRelativeDimension}~$0$~$f$ fails. The local-freeness hypothesis on $\Omega$ is therefore strictly weaker than smoothness, and the converse implication of the iff form fails on this very example.
214	\end{remark}
215	
216	\begin{remark}[The Mathlib converse lemma and its hypotheses]
217	  \label{rem:converse_lemma_hypotheses}
218	  Mathlib does provide a converse-direction lemma at the ring level,
219	  \[
220	    \texttt{Algebra.IsStandardSmooth.of\_basis\_kaehlerDifferential} \quad [\text{verified}]
221	  \]
222	  (\texttt{Mathlib.RingTheory.Smooth.StandardSmoothOfFree}). Its three hypotheses make the missing content explicit:
223	  \begin{itemize}
224	    \item \texttt{Algebra.FinitePresentation}~$A$~$B$;
225	    \item \texttt{Subsingleton (Algebra.H1Cotangent}~$A$~$B$\texttt{)} --- vanishing of the first Andr\'e--Quillen cohomology, i.e.\ formal smoothness;
226	    \item a basis $b \colon \texttt{Module.Basis}~I~B~\Omega_{B/A}$ whose range lies in the image of the universal derivation, $\mathrm{Set.range}\,(\texttt{Algebra.KaehlerDifferential.D}~A~B)$.
227	  \end{itemize}
228	  None of these three is supplied by the section-module hypothesis of the would-be iff. The first-cotangent-vanishing hypothesis in particular is the deformation-theoretic input that distinguishes ``$\Omega$ locally free'' from ``smooth''; without it, the counterexample of Remark~\ref{rem:converse_counterexample} would already break the converse. Establishing \texttt{Subsingleton (Algebra.H1Cotangent}~$A$~$B$\texttt{)} from project-side hypotheses (e.g.\ via a flatness assumption added to the input) is the work that would close the converse, and is out of autonomous-loop scope.
229	\end{remark}
230	
231	\begin{remark}[Cross-reference to Stacks 02G1]
232	  \label{rem:stacks_02G1}
233	  The standard textbook biconditional ``$f$ is smooth of relative dimension $d$ iff $f$ is flat, locally of finite presentation, and $\Omega_{X/S}$ is locally free of rank $d$'' is Stacks Tag~02G1 (and is the Noetherian-case Hartshorne~II.8, Theorem~II.5.2). The flatness conjunct is precisely what is missing from a hypothesis that only asserts local freeness of $\Omega$; supplying it amounts to the deformation-theoretic content discussed in Remark~\ref{rem:converse_lemma_hypotheses}. The forward implication proved as Theorem~\ref{thm:smooth_locally_free_omega} above corresponds to the easy direction of the same tag.
234	\end{remark}
