91	\begin{theorem}\leanok
92	[Pull-back along identity]
93	  \label{thm:Scheme_Pic_pullback_id}
94	  \lean{AlgebraicGeometry.Scheme.Pic.pullback_id}
95	  For every scheme $X$, $\mathrm{Pic.pullback}\,(\mathrm{id}_X) = \mathrm{id}_{\Pic(X)}$.
96	\end{theorem}
